args.cypher:
// Check Hall AAS for location info and hierarchical relationships
MATCH (hall:AssetAdministrationShell {idShort: 'Hall3'})-[:HAS_SUBMODEL]->(sm:Submodel)
RETURN sm.idShort, sm.id

// Get FacilityInformation content from Hall3
MATCH (sm:Submodel {id: 'urn:submodel:hall3:facilityinformation'})-[:HAS_ELEMENT*]->(p:Property)
RETURN p.idShort, p.value, p.valueType

// Check HierarchicalStructures in Hall3 for robot references
MATCH (sm:Submodel {id: 'urn:submodel:hall3:hierarchicalstructures'})-[:HAS_ELEMENT*]->(el:SubmodelElement)
RETURN el.idShort, labels(el), el.entityType

// Check Hall4 HierarchicalStructures
MATCH (sm:Submodel {id: 'urn:submodel:hall4:hierarchicalstructures'})-[:HAS_ELEMENT*]->(el:SubmodelElement)
RETURN el.idShort, labels(el), el.entityType

// Verify MiR100_001 Entity in Hall4 points to correct asset
MATCH (sm:Submodel {id: 'urn:submodel:hall4:hierarchicalstructures'})-[:HAS_ELEMENT*]->(e:Entity {idShort: 'MiR100_001'})-[:REPRESENTS_ASSET]->(a:Asset)
RETURN e.idShort, a.globalAssetId, a.assetKind
